const output = $json.output || {};
const normalizeLabel = (value) => String(value || '')
  .replace(/\u00c3\u00a1|\u00c3\u0083\u00c2\u00a1/g, 'a')
  .replace(/\u00c3\u00a9|\u00c3\u0083\u00c2\u00a9/g, 'e')
  .replace(/\u00c3\u00ad|\u00c3\u0083\u00c2\u00ad/g, 'i')
  .replace(/\u00c3\u00b3|\u00c3\u0083\u00c2\u00b3/g, 'o')
  .replace(/\u00c3\u00ba|\u00c3\u0083\u00c2\u00ba/g, 'u')
  .replace(/\u00c3\u00b1|\u00c3\u0083\u00c2\u00b1/g, 'n')
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .toLowerCase().replace(/\s+/g, ' ').trim();
const categoryKey = normalizeLabel(output.category);
const mappings = {
  'pension de alimentos': {
    canonicalCategory: 'Relaciones Paterno-Filiales y Menores',
    canonicalSubcategories: ['Pension de Alimentos'],
    metadataHints: ['rpfm:pension_alimentos'],
    searchTerms: ['pension de alimentos', 'alimentos', 'obligacion alimentaria']
  },
  'tenencia y custodia': {
    canonicalCategory: 'Relaciones Paterno-Filiales y Menores',
    canonicalSubcategories: ['Tenencia y Custodia'],
    metadataHints: ['rpfm:tenencia_custodia'],
    searchTerms: ['tenencia', 'custodia', 'regimen de visitas']
  },
  'patria potestad': {
    canonicalCategory: 'Relaciones Paterno-Filiales y Menores',
    canonicalSubcategories: ['Patria Potestad'],
    metadataHints: ['rpfm:patria_potestad'],
    searchTerms: ['patria potestad', 'derechos y deberes parentales']
  },
  'violencia familiar': {
    canonicalCategory: 'Proteccion a Personas Vulnerables',
    canonicalSubcategories: ['Violencia Familiar'],
    metadataHints: ['ppv:violencia_familiar'],
    searchTerms: ['violencia familiar', 'medidas de proteccion']
  },
  'divorcio y separacion': {
    canonicalCategory: 'Vinculos Conyugales y Patrimoniales',
    canonicalSubcategories: ['Divorcio y Separacion'],
    metadataHints: ['vcp:divorcio_separacion'],
    searchTerms: ['divorcio', 'separacion', 'fin del matrimonio']
  },
  'filiacion y paternidad': {
    canonicalCategory: 'Relaciones Paterno-Filiales y Menores',
    canonicalSubcategories: ['Filiacion e Identidad'],
    metadataHints: ['rpfm:filiacion_identidad'],
    searchTerms: ['filiacion', 'paternidad', 'reconocimiento', 'ADN']
  },
  'adopcion': {
    canonicalCategory: 'Relaciones Paterno-Filiales y Menores',
    canonicalSubcategories: ['Adopcion'],
    metadataHints: ['rpfm:adopcion'],
    searchTerms: ['adopcion', 'proceso de adopcion']
  },
  'sucesiones y herencias': {
    canonicalCategory: 'Sucesiones y Herencia',
    canonicalSubcategories: [],
    metadataHints: ['sh'],
    searchTerms: ['sucesiones', 'herencia', 'herederos', 'testamento']
  },
  'sociedad de gananciales': {
    canonicalCategory: 'Vinculos Conyugales y Patrimoniales',
    canonicalSubcategories: ['Sociedad de Gananciales'],
    metadataHints: ['vcp:sociedad_gananciales'],
    searchTerms: ['sociedad de gananciales', 'bienes del matrimonio']
  },
  'union de hecho': {
    canonicalCategory: 'Vinculos Conyugales y Patrimoniales',
    canonicalSubcategories: ['Union de Hecho'],
    metadataHints: ['vcp:union_hecho'],
    searchTerms: ['union de hecho', 'convivencia']
  },
  'tutela y curatela': {
    canonicalCategory: 'Proteccion a Personas Vulnerables',
    canonicalSubcategories: ['Tutela y Curatela'],
    metadataHints: ['ppv:tutela_curatela'],
    searchTerms: ['tutela', 'curatela', 'apoyos', 'salvaguardias']
  },
  'procedimientos administrativos': {
    canonicalCategory: 'Procesos Legales y Resolucion Alternativa',
    canonicalSubcategories: ['Conciliacion', 'Procedimiento Civil'],
    metadataHints: ['plra:conciliacion', 'plra:procedimiento_civil'],
    searchTerms: ['conciliacion', 'DEMUNA', 'procedimiento civil']
  },
  'otros': {
    canonicalCategory: 'Generales',
    canonicalSubcategories: ['Derecho de Familia', 'Otros'],
    metadataHints: ['gen:derecho_familia', 'gen:otros'],
    searchTerms: ['derecho de familia peruano']
  }
};
const fallback = mappings.otros;
return [{ json: { ...$json, retrieval: mappings[categoryKey] || fallback } }];

